import { serviceAPI } from '@/api';
export default {
  data() {
    return {
      formData: {
        name: '',
        category: '',
        price: '',
        duration: '',
        description: '',
        commissionRate: '',
        status: ''
      },
      showStatusPicker: false,
      selectedStatus: '',
      statusOptions: [{
        label: '启用',
        value: 'active'
      }, {
        label: '禁用',
        value: 'inactive'
      }]
    };
  },
  methods: {
    goBack() {
      uni.navigateBack();
    },
    getStatusLabel(value) {
      const status = this.statusOptions.find(s => s.value === value);
      return status ? status.label : '';
    },
    confirmStatus() {
      this.formData.status = this.selectedStatus;
      this.showStatusPicker = false;
    },
    async handleSubmit() {
      // 验证表单
      if (!this.formData.name || !this.formData.category || !this.formData.price || !this.formData.duration || !this.formData.status) {
        uni.showToast({
          title: '请填写所有必填项',
          icon: 'none'
        });
        return;
      }
      try {
        const res = await serviceAPI.addService(this.formData);
        if (res.success) {
          uni.showToast({
            title: '添加成功',
            icon: 'success'
          });
          setTimeout(() => {
            uni.navigateBack();
          }, 1000);
        } else {
          uni.showToast({
            title: res.message || '添加失败',
            icon: 'none'
          });
        }
      } catch (error) {
        console.error('添加服务失败:', error);
        uni.showToast({
          title: '添加失败',
          icon: 'none'
        });
      }
    }
  }
};
